		multiplesOfP := []int64{}
		for _, x := range currentNums {
			if x%p == 0 {
				multiplesOfP = append(multiplesOfP, x)
			}
		}

		if len(multiplesOfP) < 2 {
			return false
		}

		for i := 0; i < len(multiplesOfP); i++ {
			for j := i + 1; j < len(multiplesOfP); j++ {
				k := multiplesOfP[i] / p
				m := multiplesOfP[j] / p
				if gcd(k, m) == 1 {
					return true
				}
			}
		}

		return false
	}

	for _, query := range queries {
		idx := int(query[0])
		val := query[1]

		// Update nums
		nums[idx] = val

		// Check existence of good subsequence
		if isGood(nums) {
			count++
		}
	}

	return int64(count)
}
