```go
package main

import "math"

// gcd calculates the greatest common divisor of two non-negative integers.
func gcd(a, b int64) int64 {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

// checkExists checks if a "good subsequence" exists in the current nums array.
func checkExists(n int, nums []int64, p int64) bool {
	// A "good subsequence" must:
	// 1. Have length strictly less than n.
	// 2. Have GCD exactly equal to p.

	// Condition 2 implies that every element in the subsequence must be divisible by p.
	// Let's filter the array to only include multiples of p.
	multiplesOfP := []int64{}
	for _, x := range nums {
		if x%p == 0 {
			multiplesOfP = append(multiplesOfP, x)
		}
	}

	// If we have fewer than 2 elements that are multiples of p, we can't form a subsequence of length >= 2 whose GCD is p,
	// unless n=1 (which is excluded by constraints) or n=2 and we only have one multiple of p.

	// Case 1: If there are 0 or 1 multiples of p.
	if len(multiplesOfP) == 0 {
		return false
	}
	if len(multiplesOfP) == 1 {
		// A subsequence of length 1, [x], has GCD = x. If x=p, and n>1, this is a good subsequence.
		// The constraint is length < n. If n>=2, length 1 is fine.
		if multiplesOfP[0] == p {
			return true
		}
		return false
	}

	// Case 2: If there are 2 or more multiples of p.
	// We are looking for a subsequence S such that GCD(S) = p and |S| < n.

	// If we find any subset of multiples of p whose GCD is p, we win, as long as the size is < n.
	// Since we have at least 2 multiples of p (let them be m1, m2, ...), we can always form a subsequence of length 2, [m1, m2].
	// The size is 2. Since n >= 2, if n > 2, then 2 < n, and we just need GCD(m1, m2) = p.
	// If n = 2, we need |S| < 2, so |S|=1. We already checked this case (len=1 above).

	if n > 2 {
		// If n > 2, any subsequence of length 2 is valid regarding length constraint.
		// If there are at least two multiples of p, m1 and m2, we check if GCD(m1, m2) = p.
		// If GCD(m1, m2) = p, we found a good subsequence of length 2.
		// However, we need to check if *any* subsequence has GCD p.

		// The smallest possible GCD achievable by a subsequence of multiples of p is GCD(all multiples of p).
		// If GCD(all multiples of p) = p, then the subsequence consisting of all multiples of p is a candidate.
		// If |multiplesOfP| < n, we found it.
		if len(multiplesOfP) < n {
			currentGCD := multiplesOfP[0]
			for i := 1; i < len(multiplesOfP); i++ {
				currentGCD = gcd(currentGCD, multiplesOfP[i])
			}
			if currentGCD == p {
				return true
			}
		}

		// If the GCD of all of them is > p, we might still find a smaller subset.
		// Since we are dealing with GCD, the set of achievable GCDs is related to the lattice structure.
		// The problem reduces to: does there exist a subset S of multiplesOfP such that GCD(S) = p?

		// Since all elements are multiples of p, their GCD must be a multiple of p.
		// We need to check if the GCD of *all* multiples of p is exactly p.
		// If GCD(multiplesOfP) = k*p, and k>1, then any subsequence GCD will be a multiple of k*p, so it can't be p.
		// Wait, this is incorrect. Consider multiples of 2: {6, 10, 15}. If p=1.
		// If p=2, multiples are {6, 10}. GCD=2. Good.
		// If p=3, multiples are {6, 15}. GCD=3. Good.
		// If p=1, multiples are {6, 10, 15}. GCD=1. Good.

		// The necessary and sufficient condition for a subset S of {m | m % p == 0} to have GCD(S)=p
		// is that the set of numbers {m/p | m is in S} must have GCD equal to 1.

		// Let M' = {m/p | m is in multiplesOfP}. We need to check if there exists a non-empty subset S' of M' such that GCD(S') = 1.
		// This is equivalent to checking if GCD(all elements in M') = 1. (If the GCD of all elements is 1, then the whole set is the required subset).
		// If the GCD of all elements in M' is g > 1, then every subset GCD will be a multiple of g, so it cannot be 1.

		// So, we check GCD(all m/p) == 1.

		MPrime := make([]int64, len(multiplesOfP))
		for i, m := range multiplesOfP {
			MPrime[i] = m / p
		}

		if len(MPrime) == 0 { return false } // Already handled

		g := MPrime[0]
		for i := 1; i < len(MPrime); i++ {
			g = gcd(g, MPrime[i])
		}

		if g == 1 {
			// If GCD(M') = 1, then the set {multiplesOfP} itself has GCD p.
			// We need to ensure the length is < n. Since len(multiplesOfP) <= n, if len(multiplesOfP) < n, we are good.
			if len(multiplesOfP) < n {
				return true
			}
			// If len(multiplesOfP) == n, then all elements are multiples of p.
			// Since GCD(M')=1, the GCD of all elements is p.
			// But the required subsequence length must be strictly less than n.
			// If n > 1, and GCD(all) = p, we need to check if there's a proper subset whose GCD is p.

			// If n is large enough (n > 2), and GCD(M')=1, then there must exist a proper subset whose GCD is 1, unless n=2 and M'={1}.
			// Since n >= 2, if |M'| = n and GCD(M')=1, and n >= 3, there must be a proper subset whose GCD is 1 (unless M'={1, 1, ..., 1}, but then g=1).

			// This subproblem (finding a proper subset with GCD 1) is hard. Let's simplify the goal based on the constraints.

			// If we find any pair (m1, m2) such that GCD(m1/p, m2/p) = 1, then GCD(m1, m2) = p. This is a good subsequence of length 2.
			if len(multiplesOfP) >= 2 {
				for i := 0; i < len(multiplesOfP); i++ {
					for j := i + 1; j < len(multiplesOfP); j++ {
						if gcd(multiplesOfP[i]/p, multiplesOfP[j]/p) == 1 {
							return true // Found a good subsequence of length 2, and 2 < n (since n>=3 here).
						}
					}
				}
			}

			// If n=2, we need length 1, which we checked at the start.

			// If n=3, and we only found GCD(all)=p, and no pair yields p, this implies the structure is complex.
			// Given the constraints and the nature of competitive programming problems, often a small solution (length 2) suffices if one exists.
			// Since n >= 2, if n > 2, length 2 is allowed. If we find a pair whose GCD is p, we return true.

			// If we reach here, it means GCD(M')=1, but no pair yields GCD 1 in M'. This is impossible unless |M'|=1, but we are in |M'|>=2.
			// Proof sketch: If |M'| >= 2 and GCD(M')=1, there must exist a subset of size 2 whose GCD is 1, unless M'={1, 1, ..., 1} (which implies g=1 anyway).
			// Wait, {2, 3, 4}. GCD=1. Pair (2, 3) has GCD 1.
			// If GCD(M')=1 and |M'|>=2, there MUST be a pair whose GCD is 1.
			// Thus, if g == 1 and |multiplesOfP| >= 2, we must have returned true above.
			return true
		}
	}

	// Final check for small N (N=2)
	if n == 2 {
		// We need a subsequence of length 1, [x], where x=p.
		for _, x := range nums {
			if x == p {
				return true
			}
		}
	}

	return false
}

func solve(nums []int64, p int64, queries [][]int64) int64 {
	n := len(nums)
	count := int64(0)
	currentNums := make([]int64, n)
	copy(currentNums, nums)

	for _, query := range queries {
		idx := int(query[0])
		val := query[1]

		// Update nums
		currentNums[idx] = val

		// Check for good subsequence
		if checkExists(n, currentNums, p) {
			count++
		}
	}

	return count
}
